tactics.medic:
class Tactic:
    def __init__(self):
        pass
    def tick(self, me, world):
        allies = world.visible_allies()
        low = [ally for ally in allies if ally.hp * 2 < ally.max_hp]
        if low:
            ally = min(low, key=lambda a: a.hp)
            if me.can_heal(ally):
                return me.heal(ally)
        if allies:
            ally = min(allies, key=lambda a: me.distance_to(a.pos))
            if me.can_heal(ally):
                return me.heal(ally)
        return me.hold()

