tactics.medic:
class Tactic:
    def __init__(self):
        pass
    def tick(self, me, world):
        allies = world.visible_allies()
        for ally in allies:
            if ally.hp < ally.max_hp * 0.5 and me.can_heal(ally):
                return me.heal(ally)
        if allies:
            nearest = min(allies, key=lambda a: me.distance_to(a.pos))
            return me.move_toward(nearest.pos)
        return me.move_toward(world.enemy_spawn)

